SELECT organizations.org_name, regions.region_name
FROM organizations
INNER JOIN regions ON organizations.region_id = regions.region_id;

SELECT o.org_id, o.org_name, o.size
FROM organizations o
JOIN expenditures e ON o.org_id = e.org_id
WHERE e.amount < (
    SELECT AVG(amount) FROM expenditures
);

SELECT size_id, num_organizations
FROM organization_sizes
WHERE num_organizations > 100;

SELECT DISTINCT o.region_id
FROM organizations o
INNER JOIN expenditures e ON o.org_id = e.org_id;

SELECT org_id, SUM(amount) AS total_expenditure
FROM expenditures
GROUP BY org_id;

SELECT o.org_name, e.category, LOG2(e.amount) AS log_amount
FROM organizations o
INNER JOIN expenditures e ON o.org_id = e.org_id;
